<script lang="ts">
  import { groupedTimeLogs, timeLogs, activeTimeLog, formatTime, resumeTimer, deleteTimeLog, toggleBlur, update } from '../time/state';
  import { projects, selectedProjectId, projectViewMode } from '../projects/state';
  import ScopeToggle from './ScopeToggle.svelte';
  import { onMount } from 'svelte'; import { openTimeLogRequest } from '../time/open';
  let expanded = new Set<string>(); let editing: string | null = null;
  function toggleGroup(id:string){expanded = new Set(expanded); expanded.has(id)?expanded.delete(id):expanded.add(id)}
  function saveEdit(log:any){const started=Date.parse(log.startInput);const ended=log.endInput?Date.parse(log.endInput):null;update({...log,title:log.title.trim()||'Untitled time entry',description:log.description.trim(),location:log.location?.trim()||'',started_at:Number.isFinite(started)?started:log.started_at,ended_at:ended,duration_seconds:ended?Math.max(0,Math.floor((ended-started)/1000)):log.duration_seconds,project_id:log.project_id});editing=null}
  function editInput(value:number|null):string{return value?new Date(value).toISOString().slice(0,16):''}
  $: visibleGroups = $groupedTimeLogs.filter((group) => $projectViewMode === 'all' || !$selectedProjectId || group.parent.project_id === $selectedProjectId);
  $: visibleTimeLogs = $timeLogs.filter((log) => $projectViewMode === 'all' || !$selectedProjectId || log.project_id === $selectedProjectId);
  onMount(() => openTimeLogRequest.subscribe((request) => { if (request) { editing = request.id; openTimeLogRequest.set(null); } }));
</script>
<div class="time-logs-view" aria-label="Time Logs"><div class="time-toolbar"><h4>Time Logs</h4><ScopeToggle scope={$projectViewMode} onChange={(value) => projectViewMode.set(value)} /></div>{#if visibleGroups.length}<div class="log-list">{#each visibleGroups as group (group.parent.group_id)}<article class:active={group.entries.some((entry)=>entry.active)} class:blurred={group.parent.blurred}><div class="log-main"><div class="log-heading"><strong>{group.parent.title}</strong>{#if group.entries.length>1}<button class="icon-button" aria-label="Toggle time log entries" on:click={()=>toggleGroup(group.parent.group_id)}><img src={`/tmp-icons/${expanded.has(group.parent.group_id)?'disclosure':'disclosure'}.svg`} alt="" /></button><span class="badge">{group.entries.length} entries</span>{/if}{#if group.entries.some((entry)=>entry.active)}<span class="running">RUNNING</span>{/if}</div><span class="description">{group.parent.description||'No description provided'}</span><small>{new Date(group.parent.started_at).toLocaleString()} {group.parent.ended_at?'– '+new Date(group.parent.ended_at).toLocaleString():'– Running'}</small></div><time>{formatTime(group.total_seconds)}</time><div class="actions"><button on:click={()=>resumeTimer(group.parent)}><img src="/tmp-icons/circle-play.svg" alt="" /> Resume</button><button on:click={()=>editing=group.parent.id}><img src="/tmp-icons/pencil.svg" alt="" /> Edit</button><button on:click={()=>deleteTimeLog(group.parent.id)}><img src="/tmp-icons/trash.svg" alt="" /> Delete</button><button class="icon-button" aria-label="Toggle privacy blur" on:click={()=>toggleBlur(group.parent.id)}><img src={`/tmp-icons/${group.parent.blurred ? 'obfuscated' : 'obfuscation'}.svg`} alt="" /></button></div></article>{#if expanded.has(group.parent.group_id)}<div class="entries">{#each group.entries as entry (entry.id)}<article class:active={entry.active} class:blurred={entry.blurred}><div class="log-main"><div class="log-heading"><strong>{entry.title}</strong>{#if entry.active}<span class="running">RUNNING</span>{/if}</div><span class="description">{entry.description||'No description provided'}</span><small>{new Date(entry.started_at).toLocaleString()} {entry.ended_at?'– '+new Date(entry.ended_at).toLocaleString():'– Running'}</small></div><time>{formatTime(entry.duration_seconds)}</time><div class="actions"><button on:click={()=>resumeTimer(entry)}><img src="/tmp-icons/circle-play.svg" alt="" /> Resume</button><button on:click={()=>editing=entry.id}><img src="/tmp-icons/pencil.svg" alt="" /> Edit</button><button on:click={()=>deleteTimeLog(entry.id)}><img src="/tmp-icons/trash.svg" alt="" /> Delete</button><button class="icon-button" aria-label="Toggle privacy blur" on:click={()=>toggleBlur(entry.id)}><img src="/tmp-icons/obfuscation.svg" alt="" /></button></div></article>{/each}</div>{/if}{/each}</div>{:else}<div class="empty-state"><h5>No time logs yet</h5><p>Start a timer from the top bar.</p></div>{/if}</div>
{#if editing}{#each visibleTimeLogs.filter((log)=>log.id===editing) as log}<div class="backdrop" role="presentation" on:click={(event) => event.target === event.currentTarget && (editing = null)}><form class="edit-modal" on:submit|preventDefault={()=>saveEdit(log)}><header><h3>Edit Timer Event</h3><button type="button" class="close" aria-label="Close" on:click={()=>editing=null}><img src="/tmp-icons/close-x.svg" alt="" /></button></header><label>Title *<input aria-label="Time entry title" bind:value={log.title}/></label><label>Description<textarea aria-label="Time entry description" bind:value={log.description}></textarea></label><div class="two-col"><label>Start Date *<input type="datetime-local" aria-label="Start date" value={editInput(log.started_at)} on:change={(event)=>log.startInput=(event.currentTarget as HTMLInputElement).value}/></label><label>End Date<input type="datetime-local" aria-label="End date" value={editInput(log.ended_at)} on:change={(event)=>log.endInput=(event.currentTarget as HTMLInputElement).value}/></label></div><small>Duration: {formatTime(log.duration_seconds)}</small><label>Location<input aria-label="Time entry location" bind:value={log.location}/></label><label>Project<select aria-label="Time entry project" bind:value={log.project_id}>{#each $projects.filter((project)=>!project.deleted_at) as project}<option value={project.id}>{project.name}</option>{/each}</select></label><footer><button type="button" on:click={()=>editing=null}>Cancel</button><button type="submit">Save Changes</button></footer></form></div>{/each}{/if}
<style>.time-logs-view{padding:1rem}.time-toolbar,.log-heading,.actions,footer{display:flex;align-items:center;gap:.5rem}.time-toolbar{justify-content:space-between;margin-bottom:1rem}.eyebrow{margin:0;color:var(--text-muted);font-size:.68rem;text-transform:uppercase}h4{margin:.2rem 0 0;font-size:1.1rem}.scope-button,button{padding:.5rem .7rem;border:1px solid var(--border-custom);border-radius:.4rem;background:var(--bg-elevated);color:var(--text-main);cursor:pointer}.log-list{display:grid;gap:.75rem}.log-list article{display:flex;align-items:center;gap:1rem;padding:1rem 1.1rem;border:1px solid var(--border-custom);border-radius:.7rem;background:var(--bg-elevated)}.log-list article.active{border-color:var(--text-main)}.log-list article.active>.actions button:first-child,.log-list article.active .entries .actions button:first-child{display:none}.log-main{display:grid;gap:.35rem;flex:1;min-width:0}.description,small{color:var(--text-muted)}small{font-size:.75rem}.log-heading strong{font-size:1.05rem}.badge,.running{padding:.25rem .5rem;border-radius:1rem;background:var(--accent-secondary);font-size:.65rem}.running{background:var(--text-main);color:var(--bg-primary)}time{font:1.35rem ui-monospace,monospace}.actions{justify-content:flex-end}.actions button{display:inline-flex;align-items:center;gap:.3rem}.actions img,.icon-button img,.close img{width:1rem;height:1rem}.icon-button{padding:.5rem}.entries{display:grid;gap:.5rem;margin-left:1.5rem}.blurred .log-main,.blurred time{filter:blur(var(--blur-intensity))}.empty-state{text-align:center;padding:4rem;color:var(--text-muted)}.backdrop{position:fixed;inset:0;z-index:20;display:grid;place-items:center;background:rgb(0 0 0/.5)}.edit-modal{display:grid;gap:1rem;width:min(42rem,calc(100vw - 2rem));padding:2rem;border:1px solid var(--border-custom);border-radius:.7rem;background:var(--bg-primary)}.edit-modal header{display:flex;align-items:center;justify-content:space-between}.edit-modal .close{border:0;background:transparent}.edit-modal label{display:grid;gap:.35rem;color:var(--text-muted)}.edit-modal input,.edit-modal textarea,.edit-modal select{padding:.65rem;border:1px solid var(--border-custom);border-radius:.4rem;background:var(--bg-elevated);color:var(--text-main)}.edit-modal textarea{min-height:5rem}.two-col{display:grid;grid-template-columns:1fr 1fr;gap:1rem}footer{justify-content:flex-end;padding-top:1rem;border-top:1px solid var(--border-custom)}footer button:last-child{background:var(--accent-primary);color:var(--text-inverse)}@media(max-width:720px){.two-col{grid-template-columns:1fr}}</style>
